import React, { useState } from 'react';
import { tasksAPI } from '../services/api';
import { formatDateShort, getDeadlineColor } from '../utils/helpers';

export const TaskCard = ({ task, onTaskUpdated, isManager }) => {
  const [loading, setLoading] = useState(false);
  const [showExtraFields, setShowExtraFields] = useState(false);

  const deadlineInfo = getDeadlineColor(task.deadline);

  const handleStatusChange = async (newStatus) => {
    setLoading(true);
    try {
      await tasksAPI.updateTask(task._id, { status: newStatus });
      onTaskUpdated();
    } catch (err) {
      console.error('Failed to update task:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async () => {
    if (!window.confirm('Are you sure you want to delete this task?')) return;

    setLoading(true);
    try {
      await tasksAPI.deleteTask(task._id);
      onTaskUpdated();
    } catch (err) {
      console.error('Failed to delete task:', err);
    } finally {
      setLoading(false);
    }
  };

  const priorityColors = {
    low: 'bg-blue-100 text-blue-800',
    medium: 'bg-yellow-100 text-yellow-800',
    high: 'bg-red-100 text-red-800',
  };

  const statusColors = {
    pending: 'bg-gray-100 text-gray-800',
    'in-progress': 'bg-blue-100 text-blue-800',
    completed: 'bg-green-100 text-green-800',
  };

  return (
    <div className={`bg-white rounded-lg shadow-md p-5 border-l-4 ${
      task.priority === 'high' ? 'border-red-500' :
      task.priority === 'medium' ? 'border-yellow-500' :
      'border-blue-500'
    }`}>
      {/* Header */}
      <div className="mb-3">
        <h3 className="text-lg font-bold text-gray-800 mb-2">{task.title}</h3>
        <div className="flex gap-2 flex-wrap">
          <span className={`text-xs font-semibold px-2 py-1 rounded ${priorityColors[task.priority]}`}>
            {task.priority.toUpperCase()}
          </span>
          <span className={`text-xs font-semibold px-2 py-1 rounded ${statusColors[task.status]}`}>
            {task.status.toUpperCase()}
          </span>
          <span className={`text-xs font-semibold px-2 py-1 rounded ${deadlineInfo.bg} ${deadlineInfo.text}`}>
            {deadlineInfo.label}
          </span>
        </div>
      </div>

      {/* Description */}
      {task.description && (
        <p className="text-sm text-gray-600 mb-3">{task.description}</p>
      )}

      {/* Details */}
      <div className="text-sm text-gray-600 space-y-1 mb-3 pb-3 border-b">
        <p><span className="font-semibold">Department:</span> {task.department}</p>
        <p><span className="font-semibold">Assigned to:</span> {task.assignedTo.username}</p>
        <p><span className="font-semibold">Deadline:</span> {formatDateShort(task.deadline)}</p>
        {task.createdBy && (
          <p><span className="font-semibold">Created by:</span> {task.createdBy.username}</p>
        )}
      </div>

      {/* Extra Fields */}
      {Object.keys(task.extraFields || {}).length > 0 && (
        <div className="mb-3">
          <button
            onClick={() => setShowExtraFields(!showExtraFields)}
            className="text-xs text-blue-600 hover:text-blue-800 font-semibold"
          >
            {showExtraFields ? '▼' : '▶'} Additional Fields
          </button>
          {showExtraFields && (
            <div className="mt-2 bg-gray-50 p-2 rounded text-xs text-gray-700">
              {Object.entries(task.extraFields).map(([key, value]) => (
                <p key={key}><span className="font-semibold">{key}:</span> {JSON.stringify(value)}</p>
              ))}
            </div>
          )}
        </div>
      )}

      {/* Actions */}
      <div className="flex gap-2 flex-wrap">
        {task.status !== 'completed' && (
          <>
            {task.status !== 'in-progress' && (
              <button
                onClick={() => handleStatusChange('in-progress')}
                disabled={loading}
                className="text-xs px-2 py-1 bg-blue-500 text-white rounded hover:bg-blue-600 disabled:opacity-50"
              >
                In Progress
              </button>
            )}
            <button
              onClick={() => handleStatusChange('completed')}
              disabled={loading}
              className="text-xs px-2 py-1 bg-green-500 text-white rounded hover:bg-green-600 disabled:opacity-50"
            >
              Mark Complete
            </button>
          </>
        )}

        {isManager && (
          <button
            onClick={handleDelete}
            disabled={loading}
            className="text-xs px-2 py-1 bg-red-500 text-white rounded hover:bg-red-600 disabled:opacity-50"
          >
            Delete
          </button>
        )}
      </div>
    </div>
  );
};
